INSERT INTO "flashcards" VALUES(1,1,1,'A Service Catalog may include which components?','Service Catalog core components are Catalog Items, Order Guides, and Record',1,1,'2026-05-18 09:20:54.299877',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(2,1,2,'What happens when coalesce fields match during import?','Coalesce updates existing records when a match is found.',1,1,'2026-05-18 09:25:51.883872',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(3,1,3,'What does a metric do?','Metrics measure time-based performance like SLA durations.',1,1,'2026-05-18 09:26:02.269524',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(4,1,4,'What controls variable display sequence in Catalog Items?','Variable order is controlled using the Order field.',1,1,'2026-05-18 09:26:16.821785',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(5,1,5,'Reports can be created from? (Choose 2)','Reports are commonly created from list headers and View/Run module.',1,1,'2026-05-18 09:26:27.830573',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(6,1,6,'Knowledge Base search results can be sorted by? (Choose 3)','KB articles are sorted by relevance, popularity, and recency.',1,1,'2026-05-18 09:26:34.427077',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(7,1,7,'Path to fulfillment task list?','Request flow is REQ → RITM → TASK.',1,1,'2026-05-18 09:26:38.897245',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(8,1,8,'Menus/modules accessed quickly and often are called?','Favorites store frequently used modules and menus.',1,1,'2026-05-18 09:26:41.393809',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(9,1,9,'What is generated after ordering from Service Catalog?','A Service Catalog order creates a Request (REQ).',1,1,'2026-05-18 09:26:48.925727',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(10,1,10,'Actions available from User menu? (Choose 3)','User menu supports logout, role elevation, and impersonation.',1,1,'2026-05-18 09:26:52.927930',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(11,1,11,'Buttons, links, context menu items are examples of?','UI Actions create buttons, links, and menu actions.',1,1,'2026-05-18 09:26:55.233691',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(12,1,12,'Service Catalog Items are?','Catalog Items are the core building blocks of Service Catalog.',1,1,'2026-05-18 09:26:57.938781',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(13,1,13,'ACL processing order?','ACLs process from generic to specific.',1,1,'2026-05-18 09:27:00.370630',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(14,1,14,'Platform name for User table?','User table name is sys_user.',1,1,'2026-05-18 09:27:07.253644',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(15,1,15,'REQ number represents?','REQ represents the overall request/order.',1,1,'2026-05-18 09:27:11.869655',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(16,1,16,'What would NOT appear in Application Navigator History?','UI Pages do not appear in navigation history.',1,1,'2026-05-18 09:27:18.428054',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(17,1,17,'Update Set recommendation?','Never use Default Update Set for migrations.',1,1,'2026-05-18 09:27:22.661605',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(18,1,18,'What initiates a Flow?','Every flow starts with a Trigger.',1,1,'2026-05-18 09:27:27.353662',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(19,1,19,'Characteristic of Catalog variables?','Service Catalog variables are global by default.',1,1,'2026-05-18 09:27:30.957555',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(20,1,20,'Column Context Menu does what?','Column context menus support reporting, configuration, and export actions.',1,1,'2026-05-18 09:27:34.163578',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(21,1,21,'Module to create Notifications?','Notifications are created under System Notification → Email.',1,1,'2026-05-18 09:27:36.990423',3,'2026-05-15 08:45:42');
INSERT INTO "flashcards" VALUES(22,1,22,'KPI signals supporting workflow stability?','Stability signals support long-term workflow analysis.',0,0,'2026-05-15 08:45:42.381468',1,'2026-05-15 08:45:42');
