INSERT INTO "questions" VALUES(469,1,NULL,5,NULL,'( Single Topic ) What is a formatter? Select one of the following.','A formatter allows you to configure applications on your instance','A formatter is a form element used to display information that is not a field in the record','A formatter allows you to populate fields automatically','A formatter is a set of conditions applied to a table to help find and work with data','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:56','Configuring Applications for Collaboration','CSA');
