INSERT INTO "questions" VALUES(472,1,NULL,5,NULL,'( Single Topic ) What is a schema map?','A schema map enables administrators to define records from specific tables as trouble sources for Configuration Items','A schema map graphically organizes the visual task boards for the CMDB','A schema map graphically displays the Configuration Items that support a business service','A schema map displays the details of tables and their relationships in a visual manner, allowing administrators to view and easily access different parts of the database schema','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:56','Database Management and Platform Security','CSA');
INSERT INTO "questions" VALUES(473,1,NULL,5,NULL,'( Single Topic ) Which one of the following statements best describes the purpose of an Update Set?','An Update Set allows administrators to group a series of changes into a named set and then move this set as a unit to other systems','By default, an Update Set includes customizations, Business Rules, and homepages','An Update Set is a group of customizations that is moved from Production to Development','By default, the changes included in an Update Set are visible only in the instance to which they are applied','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:56','Data Migration and Integration','CSA');
