INSERT INTO "questions" VALUES(477,1,NULL,5,NULL,'( Single Topic ) When working on a form, what is the difference between Insert and Update operations?','Insert creates a new record and Update saves changes, both remain on the form','Insert creates a new record and Update saves changes, both exit the form','Insert saves changes and exits the form, Update saves changes and remains on the form','Insert saves changes and remains on the form, Update saves changes and exits the form','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:56','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(478,1,NULL,5,NULL,'( Single Topic ) How is the Event Log different from the Event Registry?','Event Log contains generated Events, the Event Registry is a table of Event definitions','Event Log is formatted in the Log style, the Event Registry displays different fields','Event Log lists Events that were triggered by integrations, the Event Registry lists the Events that were triggered during the day (24-hour period)','Event Log is the same as the Event Registry','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:56','Database Management and Platform Security','CSA');
INSERT INTO "questions" VALUES(479,1,NULL,5,NULL,'( Single Topic ) What is a Dictionary Override?','A Dictionary Override is an incoming customer update in an Update Set which applies to the same objects as a newer local customer update','A Dictionary Override is the addition, modification, or removal of anything that could have an effect on IT services','A Dictionary Override is a task within a flow that requests an action before the flow can continue','A Dictionary Override sets field properties in extended tables','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:56','Database Management and Platform Security','CSA');
