INSERT INTO "questions" VALUES(523,1,NULL,5,NULL,'( Single Topic ) Which one statement correctly describes Access Control rule evaluation?','Table access rules are evaluated from the general to the specific','If more than one rule applies to a record, the older rule is evaluated first','If a row level rule and a field level rule exist, both rules must be true before an operation is allowed','The role with the most permissions evaluates the rules first.','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:56','Database Management and Platform Security','CSA');
