INSERT INTO "questions" VALUES(650,1,NULL,5,NULL,'( Single Topic ) When looking at a long list of records, you want to quickly filter, to show only those which have Category of Hardware. How might you do that?','On the Category column header, right click and select Show > Hardware','Right click on magnifier, type Hardware and click enter','On the list, locate and right click on the value Hardware, select Show Matching','On Breadcrumb, click > icon, type Hardware and click enter','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:56','Configuring Applications for Collaboration','CSA');
