INSERT INTO "questions" VALUES(660,1,NULL,5,NULL,'( Single Topic ) A Service Catalog project will involve building 80 catalog items. For each of the catalog items, the following fields will be mandatory on the forms: • Requested for • Requested by • Approving manager • Delivery instructions All of the other variables will be specific to the individual catalog item. What features would you use when designing the catalog item form?','Create a Variable Set Template, then apply to all of the catalog items.','Create one Variable Set for the four variables, then add that variable set to each of the 80 catalog items.','Create a Record Producer that contains the four fields; then add to the record producer related list on the Catalog Items.','Create a Flow Designer Action, with Variable Set Data Pill, then apply flow to all of the 80 catalog items.','a','Refer to ServiceNow documentation for details.','medium',1,'uploaded',1,'2026-05-15 08:45:56','Configuring Applications for Collaboration','CSA');
