INSERT INTO "questions" VALUES(730,1,NULL,5,NULL,'( Single Topic ) Which path would you take to access the table configuration page from a form?','The Form Context menu > View > Show Table','The Form Context menu > View > Table','The Form Context menu > Configure > Dictionary','The Form Context menu > Configure > Table','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:57','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(731,1,NULL,5,NULL,'( Single Topic ) Which admin role is required to make changes to High Security Settings?','high_sec_admin','sn_acl_admin','admin','security_admin','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:45:57','Database Management and Platform Security','CSA');
INSERT INTO "questions" VALUES(732,1,30,6,364,'A user reports that their newly provisioned server is not being populated in the CMDB, despite the CI being created successfully through the ServiceNow ITSM module. What would be the most likely cause of this issue, given that the CMDB data source is properly configured and the necessary credentials are in place?','The CI''s discovery source is not set to populate the CMDB','The CMDB data source is not properly synchronized with the ITSM module','The server''s IP address is not correctly formatted in the CI record','The CMDB table is not properly extended to include server CI types','a','The discovery source of a CI determines where the CI data comes from, and if it''s not set to populate the CMDB, the CI won''t be added. The other options are plausible but less likely causes, as they would typically result in different symptoms or errors. For example, a synchronization issue would likely cause a delay or failure in updating existing CIs, while an incorrect IP address would cause issues with network discovery. A table extension issue would prevent the creation of server CIs altogether.','hard',1,'ai_generated',1,'2026-05-15 08:46:58','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(733,1,30,6,364,'You need to configure a new CMDB data source to synchronize CI data from an external discovery tool. The tool provides a REST API for accessing CI data, but it requires authentication using a client certificate. What would be the best approach to authenticate the ServiceNow instance with the external tool?','Use a MID Server with a configured client certificate to authenticate with the external tool','Use a ServiceNow API key to authenticate with the external tool','Configure the external tool to use a shared secret for authentication','Use a username and password to authenticate with the external tool','a','Using a MID Server with a client certificate is the most secure and reliable way to authenticate with an external tool that requires certificate-based authentication. The other options are less secure or not compatible with the required authentication method. For example, using a shared secret or username and password would not meet the certificate-based authentication requirement, while using an API key would not provide the necessary authentication mechanism.','hard',1,'ai_generated',1,'2026-05-15 08:46:58','Platform Overview and Navigation','CSA');
INSERT INTO "questions" VALUES(734,1,30,6,364,'A company has multiple business units, each with their own set of CI classes and discovery sources. The company wants to implement a centralized CMDB to provide a single, unified view of all CIs across the organization. What would be the best approach to organizing the CMDB data to support this requirement?','Create a separate CMDB table for each business unit, with a unified view table that aggregates data from all tables','Use a single CMDB table with a ''business_unit'' field to categorize CIs by business unit','Implement a hierarchical CMDB structure, with parent-child relationships between business units and their respective CIs','Use a data mart to aggregate CI data from each business unit, with a unified view provided through a reporting interface','b','Using a single CMDB table with a ''business_unit'' field is the most efficient and scalable way to organize the data, as it allows for easy filtering and categorization of CIs by business unit. The other options would introduce unnecessary complexity or limitations, such as data redundancy or performance issues. For example, using separate tables for each business unit would require complex data aggregation and synchronization, while a hierarchical structure would be difficult to maintain and query.','medium',1,'ai_generated',1,'2026-05-15 08:46:58','Platform Overview and Navigation','CSA');
INSERT INTO "questions" VALUES(735,1,30,6,366,'You are a ServiceNow CSA working on a project to implement CMDB for a large IT organization. The client wants to know the benefits of having an accurate and up-to-date CMDB. Which of the following benefits would you highlight as the most critical to the IT team?','Facilitate impact analysis of proposed changes to reduce or eliminate downtime','Locating failed changes and associated incidents','Assess problem trends pertaining to specific CIs','Efficiently manage incidents affecting CIs and service delivery','a','The correct answer is a because facilitating impact analysis of proposed changes is critical to reducing or eliminating downtime, which is a key benefit of having an accurate and up-to-date CMDB. While options b, c, and d are also benefits, they are not as critical to the IT team as option a. This is because option a directly impacts the IT team''s ability to manage changes and minimize downtime, which is a key aspect of CMDB.','hard',1,'ai_generated',1,'2026-05-15 08:47:02','Database Management and Platform Security','CSA');
INSERT INTO "questions" VALUES(736,1,30,6,366,'A user reports that they are having trouble navigating the CMDB in ServiceNow. They want to toggle between the CI Health Dashboard view and the form view. Where would you instruct them to find this option?','In the form title bar','In the CI Status Dashboard','In the CI Health Center','In the CI Service Center','a','The correct answer is a because the option to toggle between the CI Health Dashboard view and the form view is located in the form title bar. This is a key feature of the CMDB in ServiceNow, and instructing the user to look in the form title bar will allow them to easily switch between views. Options b, c, and d are incorrect because they are not relevant to toggling between views.','medium',1,'ai_generated',1,'2026-05-15 08:47:02','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(737,1,30,6,366,'You are working on a project to implement CSDM in ServiceNow. The client wants to know what CSDM is and how it will benefit their organization. Which of the following is a correct description of CSDM?','A set of reports for CMDB','CMDB code to install','Standard terms and definitions, Best Practice for CMDB Data Modeling and Data Management, and out of the box CMDB core tables','A CI Status Dashboard','c','The correct answer is c because CSDM is a framework that provides standard terms and definitions, best practices for CMDB data modeling and data management, and out of the box CMDB core tables. This framework is designed to help organizations implement a robust and effective CMDB. Options a, b, and d are incorrect because they do not accurately describe the components of CSDM.','hard',1,'ai_generated',1,'2026-05-15 08:47:02','Data Migration and Integration','CSA');
INSERT INTO "questions" VALUES(738,1,30,6,368,'A user reports that the CMDB is not accurately reflecting the relationships between Configuration Items (CIs), and as a result, service maps are not being generated correctly. To troubleshoot this issue, where would you navigate to review or create new Suggested Relationships?','ALL > System Security > Relationships > Suggested Relationships','ALL > Configuration > Relationships > Suggested Relationships','ALL > System Properties > Relationships > Suggested Relationships','ALL > Configuration > Suggested Relationships','b','The correct answer is b, because according to the content, to review or create new Suggested Relationships, you need to navigate to ALL > Configuration > Relationships > Suggested Relationships. This is the correct path to access Suggested Relationships, which is essential for accurately reflecting relationships between CIs and generating service maps. Options a, c, and d are incorrect because they do not follow the correct path.','hard',1,'ai_generated',1,'2026-05-15 08:47:07','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(739,1,30,6,368,'Your organization is implementing ServiceNow Service Mapping to overlay service maps onto existing configuration data. What approach does ServiceNow Service Mapping use to connect CIs underlying a given service, making the CMDB service aware?','Bottom-up approach','Top-down approach','Hybrid approach','Modular approach','b','The correct answer is b, because according to the content, ServiceNow Service Mapping uses a Top-down approach to overlay service maps onto existing configuration data to connect CIs underlying a given service, making the CMDB service aware. This approach is essential for accurately reflecting service relationships and dependencies. Options a, c, and d are incorrect because they do not accurately describe the approach used by ServiceNow Service Mapping.','medium',0,'ai_generated',1,'2026-05-15 08:47:07','Database Management and Platform Security','CSA');
INSERT INTO "questions" VALUES(740,1,30,6,368,'As a ServiceNow administrator, you are tasked with identifying and documenting the different types of Configuration Items (CIs) in your organization''s CMDB. Which of the following are examples of CIs that you would expect to find in the CMDB?','Only Tangible entities, such as hardware and software','Only Intangible entities, such as business services and email','Tangible entities, such as hardware and software, and Intangible entities, such as business services and email, and Configuration Item','Only Configuration Management Database and configuration_admin role','c','The correct answer is c, because according to the content, examples of CIs include both Tangible entities (e.g. hardware, software, servers) and Intangible entities (e.g. business services, email), as well as Configuration Item. These are all types of CIs that would be expected to be found in the CMDB. Options a, b, and d are incorrect because they do not accurately represent the range of CI types that would be expected to be found in the CMDB.','hard',1,'ai_generated',1,'2026-05-15 08:47:07','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(741,1,30,6,370,'A large financial services organization is implementing ServiceNow CMDB to improve their IT service management. They have a complex infrastructure with multiple data centers, cloud services, and thousands of configuration items. What is the primary benefit of using the Common Service Data Model (CSDM) in this implementation?','It provides a standardized framework for incident management','It enables true service level reporting and provides prescriptive guidance on service modeling within the CMDB','It automates the discovery and population of configuration items','It integrates with external ITSM tools to provide a unified view of IT services','b','The Common Service Data Model (CSDM) provides a standard and shared set of service-related definitions across products and platforms, enabling true service level reporting and providing prescriptive guidance on service modeling within the CMDB. This is particularly important in a large and complex organization like a financial services company, where standardized service definitions are crucial for effective IT service management. Options A, C, and D are incorrect because they do not accurately describe the primary benefit of using CSDM.','hard',1,'ai_generated',1,'2026-05-15 08:47:11','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(742,1,30,6,370,'You are a ServiceNow administrator tasked with optimizing the CMDB for a manufacturing company. The company has recently upgraded their ERP system and deployed new IoT devices on the shop floor. What type of tests should you run to ensure that the CMDB still works correctly after these changes?','Simulation tests to model potential failures','Quick start tests to verify CMDB functionality','Defect tests to identify and fix bugs','Enhancement tests to validate new features','b','Quick start tests are designed to verify that the CMDB is functioning correctly after changes such as upgrades or deployments of new applications or integrations. In this scenario, running quick start tests would help ensure that the CMDB can still discover and track configuration items, and provide accurate service level reporting. Options A, C, and D are incorrect because they do not accurately describe the type of tests needed to verify CMDB functionality after changes.','medium',1,'ai_generated',1,'2026-05-15 08:47:11','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(743,1,30,6,370,'A user reports that they are unable to view the dependency view map for a specific configuration item in the CMDB. As a ServiceNow administrator, where would you navigate to troubleshoot this issue?','Configuration > Relationships > Suggested Relationships','CIs > Relationships > Suggested Relationships','Dependency Views > View Map','Service Mapping > Map View','c','To view a dependency view map, you need to navigate to Dependency Views > View Map. This is the correct location to troubleshoot issues related to viewing dependency views. Options A and B are incorrect because they relate to creating new relationship rules, not viewing dependency views. Option D is incorrect because it relates to service mapping, not dependency views.','medium',1,'ai_generated',1,'2026-05-15 08:47:11','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(744,1,NULL,7,NULL,'When looking at a long list of records, you want to quickly filter, to show only those which have category of hardware. How might you do that?','on breadcrumbs, click > icon, type hardware and click enter','right click on the magnifier, type hardware and click enter','click funnel icon, type hardware and click enter.','on the list, locate and right click on the value Hardware, select show matching','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:47:17','Configuring Applications for Collaboration','CSA');
INSERT INTO "questions" VALUES(745,1,NULL,7,NULL,'for a customer’s inventory application, several inventory applications fields on a needed- on inventory ticket. this ticket will be assigned to inventory support team members. how would you start to implement this requirement?','create inventory table as a new base table. then add inventory specification fields as needed.','create inventory table with the inventory specification fields. in create view between the inventory and task table.','create the inventory table with the inventory specification fields. then create many to many relationships between the inventory and the task table.','create inventory table as an extended table from the task table. then add the inventory specification fields, as needed.','a','Refer to ServiceNow documentation for details.','medium',1,'uploaded',1,'2026-05-15 08:47:17','Database Management and Platform Security','CSA');
INSERT INTO "questions" VALUES(746,1,NULL,7,NULL,'what utility enables process owners to other cross enterprise workflows within a single unified process?','Flow editor','floor designer','workflow manager','process owner dashboard','a','Refer to ServiceNow documentation for details.','medium',0,'uploaded',1,'2026-05-15 08:47:17','Platform Overview and Navigation','CSA');
