INSERT INTO "questions" VALUES(758,1,NULL,7,NULL,'Which statement is true about business rules? A. A business rule must run before a database action occurs B. A business rule can be a piece of Javascript C. A business rule must not run before a database action occurs D. A business rule monitors fields on a form Answer: B 1. What section on a task record would you use to see the most recent update made to a record? i) Journal ii) Timeline iii) update log iv) audit log v) diary vi) activity 2. What are examples of UI actions, relating to lists? choose four answers?','List buttons','list context menu','list choices','list links','a','Refer to ServiceNow documentation for details.','medium',1,'uploaded',1,'2026-05-15 08:47:17','Configuring Applications for Collaboration','CSA');
