INSERT INTO "questions" VALUES(761,1,NULL,7,NULL,'Which one of the following statements describes the purpose of a Service Catalog flow?','A Service Catalog flow generates three basic components: item variable types, tasks, and approvals','Although a Service Catalog flow cannot send notifications, the flow drives complex fulfillment processes','A Service Catalog flow is used to drive complex fulfillment processes and sends notifications to defined users or groups','A Service Catalog flow generates three basic components: item variable types, tasks, and notifications','c','Explanation/Reference:','medium',0,'uploaded',1,'2026-05-15 08:47:17','Self Service & Automation','CSA');
