INSERT INTO "questions" VALUES(781,1,NULL,7,NULL,'What is the difference between a UI Policy and Data Policy?','Data Policies run when data is entered through the form, by an Import Set, or by web services, while UI Policies are set only by web services','Data Policies can be converted into UI Policies, but UI Policies cannot be converted into Data Policies','Data Policies run regardless of how data is entered into ServiceNow, while UI Policies are used for form interactions','Data Policies run only after UI Policies run successfully','c','Explanation/Reference:','medium',0,'uploaded',1,'2026-05-15 08:47:17','Data Migration and Integration','CSA');
