INSERT INTO "questions" VALUES(811,1,NULL,7,NULL,'Two departments (HR Onboarding and Facilities) have come to you, asking for a way for employees to request event room set up services. The requirements are the same for the form and the task routing to the Facilities’ assignment group. For HR, the item will be used primarily for the Onboarding coordinators, for employee orientation sessions. For Facilities, the item will be used for anyone in the company who needs room set up services. However, both departments have their own service catalogs. What do you do, to support these requirements?','Create one Catalog Item for HR Event Room Set Up and one for Facilities Event Room Set Up; then publish each to the appropriate Catalog.','Create one Catalog Item for Event Room Set Up; then publish to both Catalogs.','Create one Catalog Item for Event Room Set Up; then publish to the Parent Catalog, which is accessible to both HR and Facilities.','Create one Catalog Item for Event Room Set Up; then use ACLs to control access.','c','Explanation/Reference:','medium',1,'uploaded',1,'2026-05-15 08:47:17','Configuring Applications for Collaboration','CSA');
