CREATE TABLE mock_tests (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	test_type VARCHAR(11) NOT NULL, 
	title VARCHAR(200) NOT NULL, 
	topic_id INTEGER, 
	total_questions INTEGER NOT NULL, 
	duration_minutes INTEGER NOT NULL, 
	status VARCHAR(9), 
	score_percent FLOAT, 
	correct_count INTEGER, 
	wrong_count INTEGER, 
	skipped_count INTEGER, 
	time_taken_seconds INTEGER, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	completed_at DATETIME, exam_type VARCHAR(50) DEFAULT 'CSA', 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	FOREIGN KEY(topic_id) REFERENCES topics (id)
);
CREATE TABLE questions (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	topic_id INTEGER, 
	content_source_id INTEGER, 
	chunk_id INTEGER, 
	question_text TEXT NOT NULL, 
	option_a TEXT NOT NULL, 
	option_b TEXT NOT NULL, 
	option_c TEXT NOT NULL, 
	option_d TEXT NOT NULL, 
	correct_answer VARCHAR(1) NOT NULL, 
	explanation TEXT NOT NULL, 
	difficulty_level VARCHAR(6), 
	is_scenario_based BOOLEAN, 
	generated_by VARCHAR(12), 
	is_approved BOOLEAN, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, domain VARCHAR(255), exam_type VARCHAR(50) DEFAULT 'CSA', 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	FOREIGN KEY(topic_id) REFERENCES topics (id), 
	FOREIGN KEY(content_source_id) REFERENCES content_sources (id), 
	FOREIGN KEY(chunk_id) REFERENCES chunks (id)
);
CREATE TABLE test_questions (
	id INTEGER NOT NULL, 
	test_id INTEGER NOT NULL, 
	question_id INTEGER NOT NULL, 
